import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.BYYsWsaA.js";const n="/docs/images/getting-started-contact-list.png",m=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),s={name:"guide/getting-started.md"};function d(i,t,l,h,c,g){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>This guide walks you through creating your first sheet or document in Wafflebase.</p><h2 id="sign-in" tabindex="-1">Sign In <a class="header-anchor" href="#sign-in" aria-label="Permalink to &quot;Sign In&quot;">​</a></h2><p>Go to <a href="https://wafflebase.io" target="_blank" rel="noreferrer">wafflebase.io</a> and click <strong>Get Started</strong>. Sign in with your GitHub account.</p><h2 id="create-a-sheet-or-document" tabindex="-1">Create a Sheet or Document <a class="header-anchor" href="#create-a-sheet-or-document" aria-label="Permalink to &quot;Create a Sheet or Document&quot;">​</a></h2><p>After signing in, you&#39;ll see your workspace. Click the <strong>New</strong> dropdown button to choose what to create:</p><ul><li><strong>New Sheet</strong> — A spreadsheet for structured data, formulas, and charts</li><li><strong>New Document</strong> — A word-processor-style editor for writing and formatting text</li></ul><h2 id="try-a-sheet" tabindex="-1">Try a Sheet <a class="header-anchor" href="#try-a-sheet" aria-label="Permalink to &quot;Try a Sheet&quot;">​</a></h2><p>Select <strong>New Sheet</strong> to create a blank spreadsheet. Let&#39;s build a simple contact list. Click on cell <strong>A1</strong> and type the following data, pressing <code>Tab</code> to move right and <code>Enter</code> to move to the next row:</p><table tabindex="0"><thead><tr><th></th><th>A</th><th>B</th><th>C</th></tr></thead><tbody><tr><td>1</td><td><strong>Name</strong></td><td><strong>Email</strong></td><td><strong>Role</strong></td></tr><tr><td>2</td><td>Alice</td><td><a href="mailto:alice@example.com" target="_blank" rel="noreferrer">alice@example.com</a></td><td>Engineer</td></tr><tr><td>3</td><td>Bob</td><td><a href="mailto:bob@example.com" target="_blank" rel="noreferrer">bob@example.com</a></td><td>Designer</td></tr><tr><td>4</td><td>Carol</td><td><a href="mailto:carol@example.com" target="_blank" rel="noreferrer">carol@example.com</a></td><td>Manager</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Press <code>Tab</code> to move to the next column, <code>Enter</code> to move to the next row. Press <code>Escape</code> to cancel editing.</p></div><p>Your spreadsheet should look like this:</p><p><img src="'+n+'" alt="Contact list spreadsheet"></p><h3 id="resize-columns" tabindex="-1">Resize Columns <a class="header-anchor" href="#resize-columns" aria-label="Permalink to &quot;Resize Columns&quot;">​</a></h3><p>If the email column looks cramped, hover over the border between column headers <strong>B</strong> and <strong>C</strong>, then drag it to the right to widen column B.</p><h3 id="add-a-tab" tabindex="-1">Add a Tab <a class="header-anchor" href="#add-a-tab" aria-label="Permalink to &quot;Add a Tab&quot;">​</a></h3><p>Your document starts with one tab called <strong>Sheet1</strong>. Click the <strong>+</strong> button next to the tab bar at the bottom to add a new tab. Double-click the tab name to rename it.</p><h2 id="try-a-document" tabindex="-1">Try a Document <a class="header-anchor" href="#try-a-document" aria-label="Permalink to &quot;Try a Document&quot;">​</a></h2><p>Select <strong>New Document</strong> to open a blank page. Start typing — the editor works like a word processor. Use the toolbar to apply formatting such as <strong>bold</strong>, <em>italic</em>, and text alignment.</p><p>For a full walkthrough, see the <a href="/docs/docs-editor/writing-a-document.html">Writing a Document</a> guide.</p><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><p><strong>Sheets:</strong></p><ul><li><a href="/docs/sheets/build-a-budget.html">Build a Budget Spreadsheet</a> — Learn formulas, formatting, and layout</li><li><a href="/docs/sheets/formulas.html">Formulas</a> — Full list of supported functions</li><li><a href="/docs/sheets/charts.html">Charts &amp; Pivot Tables</a> — Visualize your data</li><li><a href="/docs/sheets/keyboard-shortcuts.html">Keyboard Shortcuts</a> — Speed up your workflow</li></ul><p><strong>Docs:</strong></p><ul><li><a href="/docs/docs-editor/writing-a-document.html">Writing a Document</a> — Text editing, formatting, and page layout</li><li><a href="/docs/docs-editor/keyboard-shortcuts.html">Keyboard Shortcuts</a> — Document editor shortcuts</li></ul><p><strong>Common:</strong></p><ul><li><a href="/docs/guide/collaboration.html">Collaboration &amp; Sharing</a> — Share and edit together in real time</li></ul>',27)])])}const p=e(s,[["render",d]]);export{m as __pageData,p as default};
